mapper.select:
SELECT id, cart_id, menu_id, quantity
FROM cart_item
WHERE cart_id = #{cartId}
  AND menu_id = #{menuId}

SELECT id
FROM menu
WHERE name       = #{name}
  AND price      = #{price}
  AND is_deleted = FALSE
LIMIT 1

mapper.update:
UPDATE cart_item
SET quantity = #{quantity}
WHERE cart_id = #{cartId}
  AND menu_id = #{menuId}

mapper.delete:
DELETE FROM cart_item
WHERE cart_id = #{cartId}
  AND menu_id = #{menuId}
